'use client';

import { AnimatePresence, motion, useReducedMotion } from 'motion/react';
import { useState, useCallback, useMemo, useEffect, useRef } from 'react';
import { useRouter } from 'next/navigation';
import { useForm } from '@tanstack/react-form';
import { useSignIn, useSignUp, useOrganizationList, useOrganizationCreationDefaults, useSession } from '@clerk/nextjs';
import { Button } from '@/components/ui/button';
import { Checkbox } from '@/components/ui/checkbox';
import { Field, FieldError, FieldGroup, FieldLabel, FieldLegend, FieldSet } from '@/components/ui/field';
import { Input } from '@/components/ui/input';
import { InputOTP, InputOTPGroup, InputOTPSlot } from '@/components/ui/input-otp';
import { REGEXP_ONLY_DIGITS } from 'input-otp';
import { RefreshCwIcon, ChevronLeftIcon, LoaderIcon, CameraIcon, XIcon } from 'lucide-react';
import { RadioGroup, RadioGroupItem } from '@/components/ui/radio-group';
import { Testimonials } from '@/components/ui/testimonials';

type Step = 'email' | 'welcome' | 'company' | 'account' | 'verify' | 'org';
type VerifyMode = 'sign_up_email_code' | 'client_trust_email_code' | null;

function toFieldErrors(errors: unknown[]): { message: string }[] {
  return errors.map(e => ({
    message: typeof e === 'string' ? e : String(e),
  }));
}

const SIGNUP_STEPS: Step[] = ['company', 'account', 'verify', 'org'];

const STEP_FIELDS: Record<Step, string[]> = {
  email: ['email'],
  welcome: ['password'],
  company: ['companySize'],
  account: ['firstName', 'lastName', 'password', 'agreedToTerms'],
  verify: ['otpCode'],
  org: ['orgName'],
};

const COMPANY_SIZES = ['1-10', '11-50', '51-200', '201-500', '501-1000', '1000+'] as const;

const QUOTES = [
  {
    quote:
      'This has completely reshaped how our team thinks about onboarding. The flow is intuitive, the defaults feel right, and our activation numbers jumped within the very first week of rolling it out.',
    cite: 'Maya Chen, CTO',
  },
  {
    quote:
      'Adopting it saved our small engineering team months of work. The primitives are flexible enough to fit our brand, secure enough for our enterprise customers, and the team behind it actually listens to feedback and ships fixes fast.',
    cite: 'Jordan Whitfield, Head of Engineering',
  },
  {
    quote:
      "We rebuilt our entire signup experience in an afternoon. It's easily the best developer experience we've had all year.",
    cite: 'Priya Anand, Co-founder',
  },
];

const dotVariants = {
  active: { width: '18px', backgroundColor: 'var(--color-foreground)' },
  completed: { width: '8px', backgroundColor: 'var(--color-foreground)' },
  upcoming: { width: '8px', backgroundColor: 'var(--color-muted-foreground)' },
};

const stepVariants = {
  enter: (dir: 1 | -1) => ({
    opacity: 0,
    filter: 'blur(4px)',
    transform: `translateX(${dir === 1 ? 40 : -40}px)`,
  }),
  center: { opacity: 1, filter: 'blur(0px)', transform: 'translateX(0px)' },
  exit: (dir: 1 | -1) => ({
    opacity: 0,
    filter: 'blur(4px)',
    transform: `translateX(${dir === 1 ? -40 : 40}px)`,
  }),
};

const stepContentVariants = {
  enter: {},
  center: { transition: { staggerChildren: 0.05 } },
  exit: {},
};

const stepItemVariants = {
  enter: (dir: 1 | -1) => ({
    opacity: 0,
    transform: `translateX(${dir === 1 ? 20 : -20}px)`,
    filter: 'blur(4px)',
  }),
  center: { opacity: 1, transform: 'translateX(0px)', filter: 'blur(0px)' },
  exit: (dir: 1 | -1) => ({
    opacity: 0,
    transform: `translateX(${dir === 1 ? -20 : 20}px)`,
    filter: 'blur(4px)',
  }),
};

export default function Home() {
  const router = useRouter();
  const { signIn, errors: signInErrors, fetchStatus: signInFetch } = useSignIn();
  const { signUp, errors: signUpErrors, fetchStatus: signUpFetch } = useSignUp();
  const { createOrganization, setActive } = useOrganizationList();
  const { data: orgDefaults } = useOrganizationCreationDefaults();
  const { session } = useSession();

  const [currentStep, setCurrentStep] = useState<Step>('email');
  const [direction, setDirection] = useState<1 | -1>(1);
  const [verifyMode, setVerifyMode] = useState<VerifyMode>(null);
  const [isCreatingOrg, setIsCreatingOrg] = useState(false);
  const [orgError, setOrgError] = useState<string | null>(null);
  const [orgLogoFile, setOrgLogoFile] = useState<File | null>(null);
  const [orgLogoPreview, setOrgLogoPreview] = useState<string | null>(null);
  const submittingRef = useRef(false);
  const shouldReduceMotion = useReducedMotion();

  const isLoading = signInFetch === 'fetching' || signUpFetch === 'fetching';

  const activeStepVariants = shouldReduceMotion
    ? {
        enter: { opacity: 0 },
        center: { opacity: 1 },
        exit: { opacity: 0 },
      }
    : stepVariants;

  const activeItemVariants = shouldReduceMotion
    ? {
        enter: { opacity: 0 },
        center: { opacity: 1 },
        exit: { opacity: 0 },
      }
    : stepItemVariants;

  const form = useForm({
    defaultValues: {
      email: '',
      companySize: '1-10',
      firstName: '',
      lastName: '',
      password: '',
      agreedToTerms: false,
      otpCode: '',
      orgName: '',
    },
    onSubmit: async () => {
      // handled via Clerk in verify step
    },
  });

  type FieldName =
    | 'email'
    | 'companySize'
    | 'firstName'
    | 'lastName'
    | 'password'
    | 'agreedToTerms'
    | 'otpCode'
    | 'orgName';

  const goTo = useCallback((step: Step, dir: 1 | -1 = 1) => {
    setDirection(dir);
    setCurrentStep(step);
  }, []);

  const validateCurrentStep = useCallback(async () => {
    const fields = STEP_FIELDS[currentStep] as FieldName[];
    const results = await Promise.all(fields.map(field => form.validateField(field, 'change')));
    for (const field of fields) {
      form.setFieldMeta(field, prev => ({ ...prev, isTouched: true }));
    }
    return results.every(errors => !errors || (Array.isArray(errors) && errors.length === 0));
  }, [form, currentStep]);

  // Revoke the object URL on unmount to avoid a memory leak
  useEffect(() => {
    return () => {
      if (orgLogoPreview) {
        URL.revokeObjectURL(orgLogoPreview);
      }
    };
  }, [orgLogoPreview]);

  // If session has a pending choose-organization task, navigate to org step
  useEffect(() => {
    if (session?.currentTask?.key === 'choose-organization' && currentStep !== 'org') {
      goTo('org');
    }
  }, [session?.currentTask?.key, currentStep, goTo]);

  // Seed org name from Clerk defaults (e.g. "Jane's Organization")
  useEffect(() => {
    if (orgDefaults?.form.name && !form.getFieldValue('orgName')) {
      form.setFieldValue('orgName', orgDefaults.form.name);
    }
  }, [orgDefaults?.form.name, form]);

  // Derive the displayed auth error from whichever Clerk hook owns the
  // current step. Field-level errors are rendered inline next to their
  // inputs, so this slot only surfaces global (non-field) errors.
  const authError = useMemo(() => {
    const useSignUpErrors =
      currentStep === 'company' ||
      currentStep === 'account' ||
      (currentStep === 'verify' && verifyMode === 'sign_up_email_code');
    const source = useSignUpErrors ? signUpErrors : signInErrors;
    return source.global?.[0]?.longMessage ?? source.global?.[0]?.message ?? null;
  }, [currentStep, verifyMode, signInErrors, signUpErrors]);

  // Single navigate handler for every signIn/signUp finalize call.
  // decorateUrl must wrap every destination URL — Safari ITP requires it
  // to return an external URL that must be navigated via window.location.
  const finalizeNavigate = useCallback(
    async ({
      session: freshSession,
      decorateUrl,
    }: {
      session?: { currentTask?: { key: string } } | null;
      decorateUrl: (url: string) => string;
    }) => {
      if (freshSession?.currentTask?.key === 'choose-organization') {
        goTo('org');
        return;
      }
      const url = decorateUrl('/');
      if (url.startsWith('https://')) {
        window.location.href = url;
      } else {
        router.push(url);
      }
    },
    [router, goTo],
  );

  const signupStepIndex = SIGNUP_STEPS.indexOf(currentStep);
  const isOnSignupFlow = signupStepIndex !== -1;
  const canGoBack = currentStep !== 'email' && currentStep !== 'org';

  const handleNext = async () => {
    if (submittingRef.current) return;
    const valid = await validateCurrentStep();
    if (!valid) return;
    submittingRef.current = true;
    try {
      if (currentStep === 'email') {
        const { error } = await signIn.create({
          identifier: form.getFieldValue('email'),
        });
        // Note: this branch only fires when user enumeration is enabled. With
        // enumeration disabled the API will not surface "identifier not found"
        // and every email will appear to exist — see README.
        const errorCode =
          error && 'errors' in error ? (error as { errors?: Array<{ code?: string }> }).errors?.[0]?.code : error?.code;
        if (errorCode === 'form_identifier_not_found') {
          goTo('company');
          return;
        }
        if (error) {
          // Any other error stays on this step; derived authError surfaces it.
          return;
        }
        goTo('welcome');
        return;
      }

      if (currentStep === 'welcome') {
        const { error } = await signIn.password({
          password: form.getFieldValue('password'),
        });
        if (error) return;
        if (signIn.status === 'complete') {
          await signIn.finalize({ navigate: finalizeNavigate });
        } else if (signIn.status === 'needs_client_trust' || signIn.status === 'needs_second_factor') {
          // This app always collects an email address, so an email-code factor
          // is guaranteed to be available for both client-trust and 2FA.
          const { error: mfaError } = await signIn.mfa.sendEmailCode();
          if (mfaError) return;
          setVerifyMode('client_trust_email_code');
          goTo('verify');
        }
        return;
      }

      if (currentStep === 'company') {
        goTo('account');
        return;
      }

      if (currentStep === 'account') {
        const { error: signUpError } = await signUp.password({
          emailAddress: form.getFieldValue('email'),
          password: form.getFieldValue('password'),
          firstName: form.getFieldValue('firstName'),
          lastName: form.getFieldValue('lastName'),
          unsafeMetadata: {
            companySize: form.getFieldValue('companySize'),
          },
        });
        if (signUpError) {
          if (signUpError.code === 'form_identifier_exists') {
            goTo('email', -1);
          }
          return;
        }
        const { error: sendError } = await signUp.verifications.sendEmailCode();
        if (sendError) return;
        setVerifyMode('sign_up_email_code');
        goTo('verify');
        return;
      }

      if (currentStep === 'verify') {
        if (verifyMode === 'sign_up_email_code' && !signUp.id) {
          goTo('email', -1);
          return;
        }
        if (verifyMode === 'client_trust_email_code' && !signIn.id) {
          goTo('email', -1);
          return;
        }

        const code = form.getFieldValue('otpCode');

        if (verifyMode === 'client_trust_email_code') {
          const { error } = await signIn.mfa.verifyEmailCode({ code });
          if (error) return;
          if (signIn.status === 'complete') {
            await signIn.finalize({ navigate: finalizeNavigate });
          }
        } else {
          const { error } = await signUp.verifications.verifyEmailCode({
            code,
          });
          if (error) return;
          if (signUp.status === 'complete') {
            await signUp.finalize({ navigate: finalizeNavigate });
          }
        }
        return;
      }

      if (currentStep === 'org') {
        const orgName = form.getFieldValue('orgName');
        if (!orgName.trim()) return;
        if (!createOrganization || !setActive) return;

        setIsCreatingOrg(true);
        setOrgError(null);
        try {
          const org = await createOrganization({ name: orgName.trim() });
          const logoFile =
            orgLogoFile ??
            (orgDefaults?.form.logo
              ? await fetch(orgDefaults.form.logo)
                  .then(r => r.blob())
                  .catch(() => null)
              : null);
          if (logoFile) {
            await org.setLogo({ file: logoFile });
          }
          await setActive({ organization: org.id });
          router.push('/');
        } catch (err) {
          setOrgError(err instanceof Error ? err.message : 'Failed to create organization');
          setIsCreatingOrg(false);
        }
        return;
      }
    } finally {
      submittingRef.current = false;
    }
  };

  const handlePrevious = () => {
    if (currentStep === 'welcome') {
      signIn.reset();
      goTo('email', -1);
      return;
    }

    if (currentStep === 'verify') {
      setVerifyMode(null);
      form.setFieldValue('otpCode', '');
      form.setFieldMeta('otpCode', prev => ({
        ...prev,
        isTouched: false,
        errors: [],
      }));
      if (verifyMode === 'sign_up_email_code') {
        signUp.reset();
        goTo('account', -1);
      } else {
        signIn.reset();
        goTo('welcome', -1);
      }
      return;
    }

    if (currentStep === 'company') {
      goTo('email', -1);
      return;
    }

    if (isOnSignupFlow && signupStepIndex > 0) {
      const prevStep = SIGNUP_STEPS[signupStepIndex - 1];
      if (prevStep) {
        goTo(prevStep, -1);
      }
    }
  };

  const handleResend = async () => {
    if (verifyMode === 'sign_up_email_code') {
      await signUp.verifications.sendEmailCode();
    } else {
      await signIn.mfa.sendEmailCode();
    }
  };

  return (
    <>
      <div className='grid flex-1 grid-cols-1 lg:grid-cols-2'>
        <main className='mx-auto flex w-full max-w-lg flex-1 flex-col'>
          <div className='flex-1 px-4 py-16 lg:px-12'>
            <header className='mb-16 flex items-center'>
              <svg
                fill='none'
                viewBox='0 0 136 26'
                className='h-7 w-auto'
                xmlns='http://www.w3.org/2000/svg'
                role='img'
                aria-label='Acme'
              >
                <g clipPath='url(#acme-logo-clip)'>
                  <path
                    fill='currentColor'
                    d='M22.4545 0C23.3949 0 24.2967 0.373538 24.9616 1.03844C25.6265 1.70334 26 2.60514 26 3.54545V22.4545C26 23.3949 25.6265 24.2967 24.9616 24.9616C24.2967 25.6265 23.3949 26 22.4545 26H3.54545C2.60514 26 1.70334 25.6265 1.03844 24.9616C0.373538 24.2967 0 23.3949 0 22.4545L0 3.54545C0 2.60514 0.373538 1.70334 1.03844 1.03844C1.70334 0.373538 2.60514 0 3.54545 0L22.4545 0ZM13.5803 5.38023C13.4574 4.74145 12.5426 4.74145 12.4197 5.38023L11.9175 7.99264C11.8975 8.09646 11.8501 8.19304 11.7801 8.2723C11.7102 8.35156 11.6202 8.41059 11.5196 8.44324C11.4191 8.4759 11.3116 8.48097 11.2084 8.45795C11.1052 8.43492 11.0101 8.38463 10.933 8.31232L8.99068 6.49409C8.51559 6.04973 7.77577 6.58746 8.05173 7.17659L9.18095 9.58573C9.22587 9.68145 9.24428 9.78748 9.23426 9.89274C9.22425 9.99801 9.18616 10.0987 9.12399 10.1842C9.06182 10.2697 8.97784 10.337 8.8808 10.379C8.78376 10.421 8.67723 10.4362 8.57232 10.423L5.93273 10.0933C5.28686 10.013 5.00441 10.8828 5.57405 11.1971L7.90341 12.4824C7.99606 12.5334 8.07332 12.6083 8.12712 12.6994C8.18093 12.7904 8.20932 12.8942 8.20932 13C8.20932 13.1058 8.18093 13.2096 8.12712 13.3006C8.07332 13.3917 7.99606 13.4666 7.90341 13.5176L5.57405 14.8029C5.00441 15.1172 5.28686 15.987 5.93273 15.9067L8.57291 15.577C8.67782 15.5638 8.78436 15.579 8.88139 15.621C8.97843 15.663 9.06241 15.7303 9.12458 15.8158C9.18675 15.9013 9.22484 16.002 9.23486 16.1073C9.24487 16.2125 9.22646 16.3185 9.18155 16.4143L8.05173 18.8234C7.77577 19.4125 8.51559 19.9503 8.99068 19.5059L10.933 17.6877C11.0101 17.6154 11.1052 17.5651 11.2083 17.542C11.3115 17.519 11.4189 17.524 11.5194 17.5566C11.62 17.5892 11.7099 17.6481 11.7799 17.7273C11.85 17.8065 11.8974 17.903 11.9175 18.0068L12.4197 20.6198C12.5426 21.2585 13.4574 21.2585 13.5803 20.6198L14.0825 18.0074C14.1025 17.9035 14.1499 17.807 14.2199 17.7277C14.2898 17.6484 14.3798 17.5894 14.4804 17.5568C14.5809 17.5241 14.6884 17.519 14.7916 17.5421C14.8948 17.5651 14.9899 17.6154 15.067 17.6877L17.0093 19.5059C17.4844 19.9503 18.2242 19.4125 17.9483 18.8234L16.819 16.4143C16.7741 16.3185 16.7557 16.2125 16.7657 16.1073C16.7758 16.002 16.8138 15.9013 16.876 15.8158C16.9382 15.7303 17.0222 15.663 17.1192 15.621C17.2162 15.579 17.3228 15.5638 17.4277 15.577L20.0673 15.9067C20.7131 15.987 20.9962 15.1172 20.426 14.8029L18.0966 13.5176C18.0039 13.4666 17.9267 13.3917 17.8729 13.3006C17.8191 13.2096 17.7907 13.1058 17.7907 13C17.7907 12.8942 17.8191 12.7904 17.8729 12.6994C17.9267 12.6083 18.0039 12.5334 18.0966 12.4824L20.426 11.1971C20.9962 10.8828 20.7131 10.013 20.0673 10.0933L17.4271 10.423C17.3222 10.4362 17.2156 10.421 17.1186 10.379C17.0216 10.337 16.9376 10.2697 16.8754 10.1842C16.8132 10.0987 16.7752 9.99801 16.7651 9.89274C16.7551 9.78748 16.7735 9.68145 16.8185 9.58573L17.9483 7.17659C18.2242 6.58746 17.4844 6.04973 17.0093 6.49409L15.067 8.31232C14.9899 8.38462 14.8948 8.43493 14.7917 8.45799C14.6885 8.48105 14.5811 8.47602 14.4806 8.44343C14.38 8.41084 14.2901 8.35189 14.2201 8.2727C14.15 8.19352 14.1026 8.09701 14.0825 7.99323L13.5803 5.38023Z'
                  />
                </g>
                <path
