                    <motion.div
                      variants={activeItemVariants}
                      custom={direction}
                    >
                      <form
                        onSubmit={e => {
                          e.preventDefault();
                          handleNext();
                        }}
                      >
                        <FieldGroup>
                          <form.Field
                            name='otpCode'
                            validators={{
                              onChange: ({ value }) => {
                                if (!value.trim()) return 'Verification code is required';
                                if (!/^\d{6}$/.test(value)) return 'Enter a 6-digit code';
                              },
                            }}
                          >
                            {field => {
                              const isInvalid = field.state.meta.isTouched && !field.state.meta.isValid;
                              const clerkCodeError =
                                verifyMode === 'client_trust_email_code'
                                  ? signInErrors?.fields?.code
                                  : signUpErrors?.fields?.code;
                              return (
                                <Field
                                  data-invalid={isInvalid || undefined}
                                  className='w-fit'
                                >
                                  <div className='flex items-center justify-between'>
                                    <FieldLabel>Verification code</FieldLabel>
                                    <Button
                                      variant='outline'
                                      size='xs'
                                      type='button'
                                      onClick={handleResend}
                                      disabled={isLoading}
                                    >
                                      <RefreshCwIcon />
                                      Resend code
                                    </Button>
                                  </div>
                                  <InputOTP
                                    pattern={REGEXP_ONLY_DIGITS}
                                    maxLength={6}
                                    value={field.state.value}
                                    onChange={value => field.handleChange(value)}
                                    onComplete={handleNext}
                                    onBlur={field.handleBlur}
                                  >
                                    <InputOTPGroup className='*:data-[slot=input-otp-slot]:size-12 *:data-[slot=input-otp-slot]:text-xl'>
                                      <InputOTPSlot index={0} />
                                      <InputOTPSlot index={1} />
                                      <InputOTPSlot index={2} />
                                      <InputOTPSlot index={3} />
                                      <InputOTPSlot index={4} />
                                      <InputOTPSlot index={5} />
                                    </InputOTPGroup>
                                  </InputOTP>
                                  {isInvalid && <FieldError errors={toFieldErrors(field.state.meta.errors)} />}
                                  {clerkCodeError && <FieldError errors={[{ message: clerkCodeError.message }]} />}
                                </Field>
                              );
                            }}
                          </form.Field>
                          {authError && <p className='text-destructive text-sm'>{authError}</p>}
                          <Button
                            type='submit'
                            disabled={isLoading}
                            size='lg'
                            className='relative w-fit'
                          >
                            {isLoading && <LoaderIcon className='absolute animate-spin' />}
                            <span className={isLoading ? 'opacity-0' : undefined}>Verify</span>
                          </Button>
                        </FieldGroup>
                      </form>
                    </motion.div>
                  </motion.div>
                )}

                {/* Create Organization */}
                {currentStep === 'org' && (
                  <motion.div
                    variants={stepContentVariants}
                    custom={direction}
                  >
                    <motion.header
                      variants={activeItemVariants}
                      custom={direction}
                      className='mb-8'
                    >
                      <h2 className='text-2xl font-semibold'>Create your organization</h2>
                      <p className='text-muted-foreground'>Set up your workspace to get started.</p>
                    </motion.header>
                    <motion.div
                      variants={activeItemVariants}
                      custom={direction}
                    >
                      <form
                        onSubmit={e => {
                          e.preventDefault();
                          handleNext();
                        }}
                      >
                        <FieldGroup>
                          <Field>
                            <FieldLabel>Logo</FieldLabel>
                            <div className='flex items-center gap-3'>
                              <div className='bg-muted relative flex size-8 shrink-0 items-center justify-center overflow-hidden rounded-md shadow-[inset_0_0_0_1px_var(--color-border)]'>
                                {orgLogoPreview || orgDefaults?.form.logo ? (
                                  <img
                                    src={orgLogoPreview ?? orgDefaults!.form.logo!}
                                    alt='Organization logo'
                                    className='size-full object-cover'
                                  />
                                ) : (
                                  <form.Subscribe selector={s => s.values.orgName}>
                                    {orgName => (
                                      <span className='text-muted-foreground text-sm font-medium'>
                                        {orgName?.charAt(0)?.toUpperCase() || '?'}
                                      </span>
                                    )}
                                  </form.Subscribe>
                                )}
                              </div>
                              <div className='grid min-w-0 flex-1 grid-cols-[1fr_2rem] items-center gap-2'>
                                <Input
                                  id='orgLogo'
                                  type='file'
                                  accept='image/*'
                                  onChange={e => {
                                    const file = e.target.files?.[0];
                                    if (file) {
                                      if (orgLogoPreview) {
                                        URL.revokeObjectURL(orgLogoPreview);
                                      }
                                      setOrgLogoFile(file);
                                      setOrgLogoPreview(URL.createObjectURL(file));
                                    }
                                  }}
                                />
                                <Button
                                  type='button'
                                  variant='ghost'
                                  size='icon'
                                  className={`size-8 ${orgLogoPreview || orgLogoFile ? 'visible' : 'invisible'}`}
                                  aria-label='Remove logo'
                                  onClick={() => {
                                    if (orgLogoPreview) {
                                      URL.revokeObjectURL(orgLogoPreview);
                                    }
                                    setOrgLogoFile(null);
                                    setOrgLogoPreview(null);
                                    const input = document.getElementById('orgLogo') as HTMLInputElement;
                                    if (input) input.value = '';
                                  }}
                                >
                                  <XIcon className='size-4' />
                                </Button>
                              </div>
                            </div>
                          </Field>
                          <form.Field
                            name='orgName'
                            validators={{
                              onChange: ({ value }) => {
                                if (!value.trim()) return 'Organization name is required';
                              },
                            }}
                          >
                            {field => {
                              const isInvalid = field.state.meta.isTouched && !field.state.meta.isValid;
                              return (
                                <Field data-invalid={isInvalid || undefined}>
                                  <FieldLabel htmlFor={field.name}>Organization name</FieldLabel>
                                  <Input
                                    id={field.name}
                                    name={field.name}
                                    placeholder='Acme Inc.'
                                    value={field.state.value}
                                    onChange={e => field.handleChange(e.target.value)}
                                    onBlur={field.handleBlur}
                                    aria-invalid={isInvalid || undefined}
                                  />
                                  {isInvalid && <FieldError errors={toFieldErrors(field.state.meta.errors)} />}
                                </Field>
                              );
                            }}
                          </form.Field>
                          {orgDefaults?.advisory?.code === 'organization_already_exists' && (
                            <p className='text-muted-foreground text-sm'>
                              An organization &ldquo;
                              {orgDefaults.advisory.meta?.organization_name}
                              &rdquo; already exists for the domain &ldquo;
                              {orgDefaults.advisory.meta?.organization_domain}
                              &rdquo;.
                            </p>
                          )}
                          {orgError && <p className='text-destructive text-sm'>{orgError}</p>}
                          <Button
                            type='submit'
                            disabled={isCreatingOrg}
                            size='lg'
                            className='relative w-fit'
                          >
                            {isCreatingOrg && <LoaderIcon className='absolute animate-spin' />}
                            <span className={isCreatingOrg ? 'opacity-0' : undefined}>Create organization</span>
                          </Button>
                        </FieldGroup>
                      </form>
                    </motion.div>
                  </motion.div>
                )}
              </motion.div>
            </AnimatePresence>
          </div>
          <AnimatePresence>
            {currentStep !== 'email' && (
              <motion.footer
                className='flex items-center justify-between gap-8 px-4 py-16 lg:px-12'
                initial={{ opacity: 0, filter: shouldReduceMotion ? 'blur(0px)' : 'blur(4px)' }}
                animate={{
                  opacity: 1,
                  filter: 'blur(0px)',
                  transition: { delay: shouldReduceMotion ? 0 : 0.15 },
                }}
                exit={{ opacity: 0, filter: shouldReduceMotion ? 'blur(0px)' : 'blur(4px)' }}
                transition={{ duration: 0.15, ease: [0.23, 1, 0.32, 1] }}
              >
                <Button
                  variant='ghost'
                  disabled={!canGoBack}
                  onClick={handlePrevious}
                >
                  <ChevronLeftIcon />
                  Back
                </Button>
                {isOnSignupFlow && (
                  <motion.div className='flex gap-1.5'>
                    {SIGNUP_STEPS.map((_, i) => (
                      <motion.div
                        key={i}
                        initial={false}
                        variants={dotVariants}
                        animate={i === signupStepIndex ? 'active' : i < signupStepIndex ? 'completed' : 'upcoming'}
                        transition={{
                          duration: 0.25,
                          ease: [0.77, 0, 0.175, 1],
                        }}
                        className='h-2 flex-none rounded-full'
                      />
                    ))}
                  </motion.div>
                )}
              </motion.footer>
            )}
          </AnimatePresence>
        </main>
        <aside
          className='border-sidebar-border bg-sidebar relative hidden items-center justify-center overflow-clip border-l px-12 lg:flex'
          style={{
            backgroundImage: 'radial-gradient(var(--color-sidebar-border) 1px, transparent 1.3px)',
            backgroundSize: '16px 16px',
            backgroundPosition: '16px 16px',
            backgroundRepeat: 'round',
          }}
        >
          <Testimonials quotes={QUOTES} />
        </aside>
      </div>
    </>
  );
}

