import type { ComponentProps } from 'react';
import { ClerkProvider } from '@clerk/nextjs';

type ClerkAppearance = NonNullable<ComponentProps<typeof ClerkProvider>['appearance']>;

/**
 * Appearance overrides that strip the default Clerk card chrome (shadow,
 * border, padding) so the component renders flush within a custom layout.
 *
 * Apply directly to any Clerk UI component via its `appearance` prop:
 *
 * ```tsx
 * import { flushCardAppearance } from '@/lib/card-appearance';
 *
 * <SignIn appearance={flushCardAppearance} />
 * ```
 */
export const flushCardAppearance: ClerkAppearance = {
  options: {
    unsafe_disableDevelopmentModeWarnings: true,
  },
  elements: {
    rootBox: 'w-full',
    cardBox: 'max-w-none !shadow-none border-0 rounded-none w-full overflow-visible',
    card: 'shadow-none border-0 rounded-none bg-transparent px-0 pt-0 pb-4 mt-0 mx-0',
    footer: 'bg-transparent border-0',
  },
};

import { clerkMiddleware, createRouteMatcher } from '@clerk/nextjs/server'

const isProtectedRoute = createRouteMatcher(['/'])

export default clerkMiddleware(async (auth, req) => {
  if (isProtectedRoute(req)) {
    await auth.protect()
  }
})

export const config = {
  matcher: [
    // Skip Next.js internals and all static files, unless found in search params
    '/((?!_next|[^?]*\\.(?:html?|css|js(?!on)|jpe?g|webp|png|gif|svg|ttf|woff2?|ico|csv|docx?|xlsx?|zip|webmanifest)).*)',
    // Always run for API routes
    '/(api|trpc)(.*)',
    // Always run for Clerk routes
    '/__clerk/(.*)',
  ],
}
